#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=1005;
int n,m,k,ans=0x3f3f3f3f;
int w[N][N],mn[N][N],mx[N][N];
void fun(int a[],int b[],int num,bool flag)
{
    deque<int> dq;
    for(int i=1;i<=num;i++)
    {
        while(!dq.empty()&&(flag^(a[i]<=a[dq.back()]))) dq.pop_back();// 1 反 0 正
        dq.push_back(i);
        while(!dq.empty()&&i-dq.front()>=k) dq.pop_front();
        b[i]=a[dq.front()];
    }
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
//  freopen(".in","r",stdin);
//  freopen(".out","w",stdout);
    cin>>n>>m>>k;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            cin>>w[i][j];
        }
    }
    for(int i=1;i<=n;i++)
    {
        fun(w[i],mn[i],m,0);
        fun(w[i],mx[i],m,1);
    }
    for(int i=k;i<=m;i++)
    {
        int t1[N],t2[N],t3[N],t4[N];
        for(int j=1;j<=n;j++)
        {
            t1[j]=mx[j][i],t2[j]=mn[j][i];
        }
        fun(t1,t3,n,1);
        fun(t2,t4,n,0);
        for(int j=k;j<=n;j++) ans=min(ans,t3[j]-t4[j]);
    }
    cout<<ans;
    return 0;
}
